#include "layer_norm_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

// UB model per tile:
//   inQueueX: 1 * innerSize floats
//   inQueueWeight: 1 * innerSize floats (but weight is same for all batches, we can load once)
//   inQueueBias: 1 * innerSize floats
//   outQueueY: 1 * innerSize floats
//   tmpQueue: 3 * innerSize floats (for mean, variance, normalized)
//   total floats ~ 6 * innerSize => bytes 24 * innerSize
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // conservative per-core share
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 32768; // max innerSize we attempt to load

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    LayerNormCustomTilingData tiling;
    const gert::Shape *inputShape = context->GetInputShape(0);
    const gert::Shape *weightShape = context->GetInputShape(1);
    // Weight shape is the normalized shape (e.g., features, dim1, dim2)
    uint32_t totalDim = static_cast<uint32_t>(inputShape->GetOriginShape().GetShapeSize());
    uint32_t innerSize = static_cast<uint32_t>(weightShape->GetOriginShape().GetShapeSize());
    uint32_t totalBatchSize = totalDim / innerSize; // number of independent items

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    float eps = 1.0f;
    if (attrs->GetAttrNum() > 0) {
        eps = *attrs->GetAttrPointer<float>(0);
    }

    // Determine tileBatchSize: we will process one batch item per iteration.
    // UB usage per item: load x, weight, bias (but weight/bias can be reused? We'll load once per block, not per batch item.
    // Actually weight and bias are the same for all batch items, but we can load them once per block.
    // For simplicity, we will load weight/bias once per block in the kernel, and then process batch items.
    // So per tile we need: 2 * innerSize (x and y) + 2 * innerSize (tmp for mean, var) + maybe extra.
    // We'll assume UB can hold 2 * innerSize for x and y, plus 3 * innerSize for intermediates.
    // Total bytes = (2 + 3) * innerSize * 4 = 20 * innerSize.
    uint32_t maxInner = UB_BUDGET_BYTES / 20; // elements
    maxInner = AlignDown(maxInner, ALIGN_ELEMS);
    if (maxInner < ALIGN_ELEMS) maxInner = ALIGN_ELEMS;
    if (maxInner > HARD_CAP_ELEMS) maxInner = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    // If innerSize exceeds maxInner, we need to tile within the inner dimension.
    // For simplicity, assume innerSize <= maxInner (otherwise we would need a more complex kernel).
    uint32_t tileBatchSize = 1; // one batch item per tile iteration

    // Block dim: assign batch items to cores, at most one item per core per iteration.
    uint32_t blockDim = CeilDiv(totalBatchSize, tileBatchSize);
    if (blockDim > 24) blockDim = 24;
    if (blockDim < 1) blockDim = 1;
    context->SetBlockDim(blockDim);

    tiling.set_totalBatchSize(totalBatchSize);
    tiling.set_innerSize(innerSize);
    tiling.set_tileBatchSize(tileBatchSize);
    tiling.set_blockDim(blockDim);
    tiling.set_eps(eps);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
